import { useEffect, useState } from "react";
import style from "./App.module.css";
import AOS from "aos";
import "aos/dist/aos.css";

function TabContents(props) {
  const [cats, setCats] = useState([]);
  const [Newcats, setNewCats] = useState([]);
  const [Favcats, setFavCats] = useState([]);
  const [Loading, setLoading] = useState(true);

  useEffect(() => {
    fetch("https://api.thecatapi.com/v1/images/search?limit=8")
      .then((response) => response.json())
      .then((json) => {
        setCats(json);
      });
    AOS.init();
    setLoading(false);
  }, [Newcats]);

  function NewCats() {
    setNewCats([]);
  }

  function Favocats(event) {
    const x = event.target.src;
    console.log(` fav: ${Favcats}`);
    const arr = [x, ...new Set(Favcats)];
    const arr2 = Array.from(new Set(arr));
    console.log(arr2);
    setFavCats(arr2);
    // setFavCats([x, ...Favcats]);
  }
  function DelCats(event) {
    const x = event.target.src;
    // setFavCats([x, ...Favcats]);
    setFavCats(Favcats.filter((value) => value !== x));
    console.log(Favcats);
  }

  if (props.clickTab === 0) {
    return Loading ? (
      <div className="loading">Loading...</div>
    ) : (
      <div>
        <div className="gallery text-center ">
          {cats.map((cat, index) => (
            <span key={cat.id}>
              <img
                data-aos="fade-up"
                onClick={Favocats}
                src={cat.url}
                className="shadow-1-strong rounded"
              />
            </span>
          ))}
        </div>{" "}
        <div className="bnt text-center m-5">
          <button onClick={NewCats} type="button" className="btn btn-secondary">
            Lets's change cats :3
          </button>
        </div>
      </div>
    );
  } else if (props.clickTab === 1) {
    return (
      <div className="gallery text-center ">
        {Favcats.map((cat, index) => (
          <span key={cat}>
            <img
              data-aos="fade-up"
              id={cat}
              src={cat}
              onClick={DelCats}
              className="shadow-1-strong rounded"
            />
          </span>
        ))}
      </div>
    );
  } else if (props.clickTab === 2) {
    return (
      <div className={style.contact}>
        <h1> 해륜</h1>
        <h3> 📧 haeryun805@gmail.com</h3>
      </div>
    );
  }
}
export default TabContents;
